    def rolling_median(samples, window=5):
        out = []
        for i in range(len(samples)):
            lo = max(0, i - window + 1)
            chunk = sorted(samples[lo:i + 1])
            mid = len(chunk) // 2
            if len(chunk) % 2 == 0:
                out.append((chunk[mid - 1] + chunk[mid]) / 2)
            else:
                out.append(chunk[mid])
        return out

    def summarize(samples):
        medians = rolling_median(samples)
        return {"peak": max(medians), "last": medians[-1]}

